section.para:
			Given a document that already carries tokens, entities, and dependency
			arcs for Acme Corp acquired Bolt in 2024., two patterns fire
			once each: an acquisition between the two organizations, and an
			acquisition date linking the object organization to the date.
			RelationExtractionExampleTest asserts the behavior shown
			here.

RelationAnnotator annotator = new RelationAnnotator(List.of(
    new RelationPattern("acquisition", "<nsubj >obj", "acquired"),
    new RelationPattern("acquisition_date", "<obj >obl", null)));

Document annotated = annotator.annotate(documentWithTokensEntitiesDeps);

List<Annotation<RelationMention>> relations =
    annotated.get(RelationAnnotator.RELATIONS);
// acquisition: entities 0 -> 1 over "Acme Corp acquired Bolt"
// acquisition_date: entities 1 -> 2 over "Bolt in 2024"
